var n = 180 + R.int(120);
var flakes = [];
for (var i = 0; i < n; i++) {
  flakes.push({
    x: R.dec() * dimensionContext.width,
    y: R.dec() * dimensionContext.height,
    vy: 0.7 + R.dec() * 2.8,
    vx: (R.dec() - 0.5) * 0.6,
    size: 0.8 + R.dec() * 2.4,
    spin: (R.dec() - 0.5) * 0.05,
    phase: R.dec() * Math.PI * 2,
    hue: R.dec() < 0.5 ? 190 + R.dec() * 25 : 300 + R.dec() * 25,
    alpha: 0.35 + R.dec() * 0.55
  });
}
return Object.assign({}, state, { flakes: flakes });
